Given your stack (Kotlin, gRPC internal, REST external, PostgreSQL 14), here's the simplest approach:

**REST endpoint** for external merchant-facing verification, with a **gRPC call** to account-service for the actual bank account validation.

```kotlin
// payment-processing/src/main/kotlin/com/helios/payment/api/MerchantVerificationController.kt

@RestController
@RequestMapping("/api/v1/merchants")
class MerchantVerificationController(
    private val verificationService: MerchantVerificationService
) {
    @PostMapping("/{merchantId}/bank-account/verify")
    suspend fun verifyBankAccount(
        @PathVariable merchantId: UUID,
        @Valid @RequestBody request: VerifyBankAccountRequest
    ): ResponseEntity<VerifyBankAccountResponse> {
        val result = verificationService.verify(merchantId, request)
        return ResponseEntity.ok(result)
    }
}

data class VerifyBankAccountRequest(
    @field:NotBlank val routingNumber: String,
    @field:NotBlank val accountNumber: String,
    val accountType: AccountType = AccountType.CHECKING
)

data class VerifyBankAccountResponse(
    val merchantId: UUID,
    val status: VerificationStatus,
    val verifiedAt: Instant? = null
)

enum class VerificationStatus { PENDING, VERIFIED, FAILED }
enum class AccountType { CHECKING, SAVINGS }
```

```kotlin
// payment-processing/src/main/kotlin/com/helios/payment/service/MerchantVerificationService.kt

@Service
class MerchantVerificationService(
    private val accountServiceClient: AccountServiceGrpcClient,
    private val verificationRepo: VerificationRepository
) {
    suspend fun verify(merchantId: UUID, request: VerifyBankAccountRequest): VerifyBankAccountResponse {
        // Validate merchant exists via gRPC to account-service
        accountServiceClient.getMerchant(merchantId)
            ?: throw ResponseStatusException(HttpStatus.NOT_FOUND, "Merchant not found")

        val verification = verificationRepo.save(
            BankAccountVerification(
                merchantId = merchantId,
                routingNumber = request.routingNumber,
                accountNumberHash = request.accountNumber.sha256(),
                accountType = request.accountType,
                status = VerificationStatus.PENDING
            )
        )

        return VerifyBankAccountResponse(
            merchantId = merchantId,
            status = verification.status
        )
    }
}
```

